mapper.select:
SELECT COUNT(*) FROM bookings
WHERE venue_id = #{venueId}
AND booking_date = #{date}
AND status = 2
AND (time_slots & #{mask}) != 0

SELECT id, venue_id, user_id, booking_date, time_slots, status, purpose, p_count, contact_info, version, created_at, updated_at
FROM bookings
WHERE id = #{id}

SELECT id, venue_id, user_id, booking_date, time_slots, status, purpose, p_count, contact_info, version, created_at, updated_at
FROM bookings
WHERE venue_id = #{venueId}
  AND booking_date BETWEEN #{startDate} AND #{endDate}
  AND status = 2
ORDER BY booking_date ASC

SELECT id, venue_id, user_id, booking_date, time_slots, status, purpose, p_count, contact_info, version, created_at, updated_at
FROM bookings
WHERE venue_id = #{venueId}
  AND user_id = #{userId}
  AND booking_date BETWEEN #{startDate} AND #{endDate}
ORDER BY booking_date ASC

SELECT id, venue_id, user_id, booking_date, time_slots, status, purpose, p_count, contact_info, version, created_at, updated_at
FROM bookings
WHERE venue_id = #{venueId}
AND booking_date = #{date}
AND status = 1
AND (time_slots & #{mask}) != 0
AND id != #{excludeBookingId}

SELECT
    b.id,
    v.name AS venue_name,
    b.booking_date,
    b.time_slots AS slots,
    b.status,
    b.created_at,
    b.purpose,
    b.p_count,
    b.contact_info
FROM bookings b
INNER JOIN venues v ON b.venue_id = v.id
WHERE b.user_id = #{userId}

    AND b.venue_id = #{venueId}


    AND b.status IN

        #{status}



    AND b.booking_date >= #{startDate}


    AND b.booking_date <= #{endDate}

ORDER BY b.created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(DISTINCT b.id)
FROM bookings b
WHERE b.user_id = #{userId}

    AND b.venue_id = #{venueId}


    AND b.status IN

        #{status}



    AND b.booking_date >= #{startDate}


    AND b.booking_date <= #{endDate}
